#include<bits/stdc++.h>
#define LL long long
#define pb push_back
using namespace std;
const int N = 1005;
struct node{LL x,Q;}a[N];
vector<int> g[N];queue<int> q;
LL n,E,dis[N][N],dp[N],ans;bool flag[N];
bool cmp(node d1,node d2){return d1.Q<d2.Q;}
void BFS(int St){
    while(!q.empty())q.pop();
    for(int i=1;i<=n;i++)flag[i]=0;
    dis[St][St]=0,flag[St]=1;q.push(St);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int v:g[u])if(!flag[v]&&dis[St][v]>dis[St][u]+E)
            dis[St][v]=dis[St][u]+E,flag[v]=1,q.push(v);
    }
    return;
}
int main(){
    //freopen("buffet.in","r",stdin);
    //freopen("buffet.out","w",stdout);
    cin>>n>>E;
    for(int i=1;i<=n;i++){
        int tmp;cin>>a[i].Q>>tmp;a[i].x=i;
        while(tmp--){int x;cin>>x;g[i].pb(x);}
    }
    memset(dis,0x3f,sizeof(dis));
    for(int i=0;i<=n;i++)dis[0][i]=0,BFS(i);
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)for(int j=0;j<i;j++)
        dp[i]=max(dp[i],dp[j]-dis[a[j].x][a[i].x]+a[i].Q);
    for(int i=1;i<=n;i++)ans=max(ans,dp[i]);cout<<ans<<"\n";
    return 0;
}
